import json
import re

# Load data
fp = open('var_functions.query_db_64', 'r')
packages = json.load(fp)
fp.close()

fm = open('var_functions.query_db_66', 'r')
mappings = json.load(fm)
fm.close()

fi = open('var_functions.query_db_42', 'r')
info = json.load(fi)
fi.close()

# Find latest version per package
latest = {}
for pkg in packages:
    try:
        vi = json.loads(pkg['VersionInfo'])
        name = pkg['Name']
        if name not in latest or vi['Ordinal'] > latest[name]['Ordinal']:
            latest[name] = {'Name': name, 'Version': pkg['Version'], 'Ordinal': vi['Ordinal']}
    except:
        pass

# Map to projects
lookup = {(m['Name'], m['Version']): m['ProjectName'] for m in mappings}

matched = []
for pkg in latest.values():
    key = (pkg['Name'], pkg['Version'])
    if key in lookup:
        matched.append({'Package': pkg['Name'], 'Version': pkg['Version'], 'Project': lookup[key]})

# Extract stars
stars = {}
for rec in info:
    txt = rec['Project_Information']
    m = re.search(r'(\d+(?:,\d+)*)\s+stars', txt)
    if m:
        count = int(m.group(1).replace(',', ''))
        pm = re.search(r'project\s+([\w-]+/[\w-]+)', txt)
        if pm:
            stars[pm.group(1)] = count

# Combine
results = []
for pkg in matched:
    proj = pkg['Project']
    if proj in stars:
        results.append({'package': pkg['Package'], 'version': pkg['Version'], 'project': proj, 'stars': stars[proj]})

# Top 5
top5 = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps(top5, indent=2))

