import json
import re
import os

# Load the NPM release packages file (this is var_functions.query_db_74 or similar)
pkg_file = None
for fname in os.listdir('.'):
    if 'query_db' in fname and '74' in fname:
        pkg_file = fname
        break

if not pkg_file:
    # Try other query_db files
    for fname in os.listdir('.'):
        if 'query_db' in fname:
            with open(fname, 'r') as f:
                test = json.load(f)
            if test and 'VersionInfo' in str(test[0]):
                pkg_file = fname
                break

# Load project mappings file
map_file = None
for fname in os.listdir('.'):
    if 'query_db' in fname and '78' in fname:
        map_file = fname
        break

if not map_file:
    for fname in os.listdir('.'):
        if 'query_db' in fname and 'ProjectName' in str(json.load(open(fname, 'r'))[0]):
            map_file = fname
            break

# Load project info file
info_file = None
for fname in os.listdir('.'):
    if 'query_db' in fname and '42' in fname:
        info_file = fname
        break

if not info_file:
    for fname in os.listdir('.'):
        if 'query_db' in fname:
            with open(fname, 'r') as f:
                test = json.load(f)
            if test and 'Project_Information' in test[0]:
                info_file = fname
                break

print('Files found:', pkg_file, map_file, info_file)

with open(pkg_file, 'r') as f:
    packages = json.load(f)

with open(map_file, 'r') as f:
    mappings = json.load(f)

with open(info_file, 'r') as f:
    info = json.load(f)

print('Data sizes:', len(packages), len(mappings), len(info))

# Step 1: Find latest release version per package
latest = {}
for p in packages:
    name = p['Name']
    vi_str = p['VersionInfo']
    vi = json.loads(vi_str)
    ordinal = vi['Ordinal']
    if name not in latest:
        latest[name] = {key: value for key, value in p.items()}
    elif ordinal > latest[name]['Ordinal']:
        latest[name] = {key: value for key, value in p.items()}
        latest[name]['Ordinal'] = ordinal

# Add ordinal to each latest package
for name in latest:
    vi = json.loads(latest[name]['VersionInfo'])
    latest[name]['Ordinal'] = vi['Ordinal']

# Step 2: Create project lookup
proj_lookup = {}
for m in mappings:
    proj_lookup[(m['Name'], m['Version'])] = m['ProjectName']

# Step 3: Match packages to projects
matched = []
for name, data in latest.items():
    key = (name, data['Version'])
    if key in proj_lookup:
        matched.append({'Package': name, 'Version': data['Version'], 'Project': proj_lookup[key], 'Ordinal': data['Ordinal']})

# Step 4: Extract star counts
star_counts = {}
for rec in info:
    txt = rec['Project_Information']
    star_match = re.search(r'([0-9,]+)\s+stars', txt)
    if star_match:
        stars = int(star_match.group(1).replace(',', ''))
        proj_match = re.search(r'project\s+([\w-]+/[\w-]+)', txt)
        if proj_match:
            project = proj_match.group(1)
            star_counts[project] = stars

# Step 5: Combine and find top 5
results = []
for pkg in matched:
    project = pkg['Project']
    if project in star_counts:
        results.append({'package': pkg['Package'], 'version': pkg['Version'], 'project': project, 'stars': star_counts[project]})

# Sort and get top 5
top5 = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

print('\nTOP 5 NPM Packages by GitHub Stars:')
for rank, pkg in enumerate(top5, 1):
    print(f"{rank}. {pkg['project']}")
    print(f"   Package: {pkg['package']} ({pkg['version']})")
    print(f"   Stars: {pkg['stars']:,}")
    print()

# Return result
result_str = json.dumps(top5, indent=2)
print('__RESULT__:')
print(result_str)

