import json
import re
import os

# Load data from the most recent query results
# We know from previous results these files exist and contain the data we need

# 1. NPM packages with release versions
packages = []
for fname in os.listdir('.'):
    if 'query_db' in fname and fname.endswith('.json'):
        with open(fname, 'r') as f:
            data = json.load(f)
        if data and len(data) > 0:
            if 'Name' in data[0] and 'VersionInfo' in data[0]:
                packages.extend(data)
                print(f"Loaded {len(data)} packages from {fname}")

# 2. Project mappings
mappings = []
for fname in os.listdir('.'):
    if 'query_db' in fname and fname.endswith('.json'):
        with open(fname, 'r') as f:
            data = json.load(f)
        if data and len(data) > 0:
            if 'ProjectName' in data[0] and 'Name' in data[0]:
                mappings.extend(data)
                print(f"Loaded {len(data)} mappings from {fname}")

# 3. Project info with stars
project_info = []
for fname in os.listdir('.'):
    if 'query_db' in fname and fname.endswith('.json'):
        with open(fname, 'r') as f:
            data = json.load(f)
        if data and len(data) > 0:
            if 'Project_Information' in data[0]:
                project_info.extend(data)
                print(f"Loaded {len(data)} info records from {fname}")

print(f"\nTotal loaded: {len(packages)} packages, {len(mappings)} mappings, {len(project_info)} info records")

# Find latest version for each package (max ordinal)
latest_packages = {}
for pkg in packages[:5000]:  # Limit for performance initially
    name = pkg['Name']
    try:
        vi = json.loads(pkg['VersionInfo'])
        ordinal = vi['Ordinal']
        if name not in latest_packages or ordinal > latest_packages[name].get('ordinal', 0):
            latest_packages[name] = {"version": pkg['Version'], "ordinal": ordinal}
    except:
        continue

print(f"Found {len(latest_packages)} latest release versions")

# Create project lookup
project_lookup = {}
for m in mappings[:5000]:
    key = (m['Name'], m['Version'])
    project_lookup[key] = m['ProjectName']

# Match packages to GitHub projects
matched = []
for name, data in list(latest_packages.items())[:2000]:
    key = (name, data['version'])
    if key in project_lookup:
        matched.append({
            "package": name,
            "version": data['version'],
            "project": project_lookup[key]
        })

print(f"Matched {len(matched)} packages to projects")

# Extract star counts
star_counts = {}
for rec in project_info[:2000]:
    txt = rec['Project_Information']
    star_match = re.search(r"([0-9,]+)\s+stars", txt)
    if star_match:
        stars = int(star_match.group(1).replace(',', ''))
        proj_match = re.search(r"project\s+([\w-]+/[\w-]+)", txt)
        if proj_match:
            star_counts[proj_match.group(1)] = stars

print(f"Extracted star counts for {len(star_counts)} projects")

# Combine and find top 5
results = []
for pkg in matched:
    project = pkg['project']
    if project in star_counts:
        results.append({
            "package": pkg['package'],
            "version": pkg['version'],
            "project": project,
            "stars": star_counts[project]
        })

# Sort and get top 5
top5 = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

# Print results
print("\n=== TOP 5 NPM PACKAGES BY GITHUB STARS ===")
for rank, pkg in enumerate(top5, 1):
    print(f"{rank}. {pkg['project']}")
    print(f"   Package: {pkg['package']} (v{pkg['version']})")
    print(f"   Stars: {pkg['stars']:,}")

# Return final result
result_json = json.dumps(top5, indent=2)
print("\n__RESULT__:")
print(result_json)

