import json
import re
import os

# Load data from available files
files = os.listdir('.')
query_files = [f for f in files if 'query_db' in f and f.endswith('.json')]

# Get the data files by their content
package_data = []
mapping_data = []
info_data = []

for f in sorted(query_files):
    try:
        with open(f, 'r') as file:
            data = json.load(file)

        if not data or len(data) == 0:
            continue

        first = data[0]

        if 'VersionInfo' in first and 'Name' in first:
            package_data = data
            print('Packages from', f, ':', len(data))
        elif 'ProjectName' in first and 'Name' in first:
            mapping_data = data
            print('Mappings from', f, ':', len(data))
        elif 'Project_Information' in first:
            info_data = data
            print('Project info from', f, ':', len(data))
    except:
        continue

print('\nLoaded:', len(package_data), 'packages,', len(mapping_data), 'mappings,', len(info_data), 'info records')

# Step 1: Find latest version for each package (max ordinal)
latest = {}
for rec in package_data:
    try:
        name = rec['Name']
        version = rec['Version']
        vi = json.loads(rec['VersionInfo'])
        ordinal = vi['Ordinal']

        if name not in latest or ordinal > latest[name]['ordinal']:
            latest[name] = {'version': version, 'ordinal': ordinal}
    except:
        pass

print('\nLatest versions found:', len(latest))

# Step 2: Create project lookup table
lookup = {}
for rec in mapping_data:
    lookup[(rec['Name'], rec['Version'])] = rec['ProjectName']

# Step 3: Match packages to projects
matched = []
for name, data in latest.items():
    key = (name, data['version'])
    if key in lookup:
        matched.append((name, data['version'], lookup[key]))

print('Matched packages:', len(matched))

# Step 4: Extract star counts
stars = {}
for rec in info_data:
    try:
        txt = rec['Project_Information']
        star_match = re.search(r'([0-9,]+) stars', txt)
        proj_match = re.search(r'project ([\w-]+/[\w-]+)', txt)
        if star_match and proj_match:
            stars[proj_match.group(1)] = int(star_match.group(1).replace(',', ''))
    except:
        pass

print('Star counts extracted:', len(stars))

# Step 5: Combine and sort
results = []
for name, version, project in matched:
    if project in stars:
        results.append([name, version, project, stars[project]])

# Sort by stars descending and get top 5
top5 = sorted(results, key=lambda x: x[3], reverse=True)[:5]

print('\nTOP 5 NPM PACKAGES BY GITHUB STARS')
print('=' * 40)
for i, (name, version, project, stars) in enumerate(top5, 1):
    print(i, '.', project)
    print('   Package:', name, '(v' + version + ')')
    print('   Stars:', stars)
    print()

# Return JSON result
output = []
for name, version, project, stars in top5:
    output.append({
        'package': name,
        'version': version,
        'project': project,
        'stars': stars
    })

result_json = json.dumps(output, indent=2)
print('__RESULT__:')
print(result_json)

